'use client';
import { useState } from 'react';
import { login, register } from '@/lib/api';

export default function AuthPage() {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [message, setMessage] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setMessage('');
    try {
      if (mode === 'login') {
        const result = await login(email, password);
        localStorage.setItem('token', result.access_token);
        setMessage(`登录成功！Token: ${result.access_token.substring(0, 20)}...`);
      } else {
        const result = await register(email, name, password);
        setMessage(`注册成功！用户: ${result.email}`);
        setMode('login');
      }
    } catch (err) {
      setMessage(`错误: ${err}`);
    }
  };

  return (
    <div style={{ padding: '2rem', maxWidth: '400px', margin: '0 auto' }}>
      <h1>LegalFlow Studio - 认证</h1>

      <div style={{ marginBottom: '1rem' }}>
        <button onClick={() => setMode('login')} style={{ marginRight: '0.5rem' }}>
          登录
        </button>
        <button onClick={() => setMode('register')}>注册</button>
      </div>

      <form onSubmit={handleSubmit}>
        <div style={{ marginBottom: '1rem' }}>
          <label>邮箱:</label>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            style={{ display: 'block', width: '100%', padding: '0.5rem' }}
          />
        </div>

        {mode === 'register' && (
          <div style={{ marginBottom: '1rem' }}>
            <label>姓名:</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              style={{ display: 'block', width: '100%', padding: '0.5rem' }}
            />
          </div>
        )}

        <div style={{ marginBottom: '1rem' }}>
          <label>密码:</label>
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            style={{ display: 'block', width: '100%', padding: '0.5rem' }}
          />
        </div>

        <button type="submit" style={{ padding: '0.5rem 1rem' }}>
          {mode === 'login' ? '登录' : '注册'}
        </button>
      </form>

      {message && (
        <div style={{ marginTop: '1rem', padding: '1rem', background: '#f0f0f0' }}>
          {message}
        </div>
      )}

      <div style={{ marginTop: '2rem' }}>
        <a href="/dashboard">返回 Dashboard</a>
      </div>
    </div>
  );
}

